refsection.programlisting:
[x, y] = meshgrid(1:260, 1:180);

solid = (x - 45).^2 + (y - 50).^2 <= 25^2;
ring = ((x - 125).^2 + (y - 50).^2 <= 30^2) ..
     & ((x - 125).^2 + (y - 50).^2 >= 13^2);

plate = (x >= 130) & (x <= 235) & (y >= 105) & (y <= 165);
holes = ((x - 160).^2 + (y - 135).^2 < 12^2) ..
      | ((x - 205).^2 + (y - 135).^2 < 12^2);

mask = solid | ring | (plate & ~holes);
filled = imfill(mask);

eulerWithHoles = imbweuler(mask, 8);
eulerFilled = imbweuler(filled, 8);

figure("figure_size", [900 400]);
subplot(1, 2, 1);
imshow(mask);
xtitle(msprintf("3 objects - 3 holes: Euler number = %d", eulerWithHoles));

subplot(1, 2, 2);
imshow(filled);
xtitle(msprintf("3 objects - 0 holes: Euler number = %d", eulerFilled));
